import './App.css';
import { Navbar, Nav, Container, Button } from "react-bootstrap";
import 'bootstrap/dist/css/bootstrap.min.css';
import bank from './bank.avif';
import { HashRouter, Routes, Route, Link } from 'react-router-dom';
import Deposit from './deposit';
import Cashback from './cashback';
import Register from './register';
import Login from './login';
import Alldata from './alldata';
import TransactionHistory from './TransactionHistory';
import Profile from './Profile';
import Carousel from 'react-bootstrap/Carousel';
import Slide1 from './sile1.avif';
import Slide2 from './sile2.avif';
import Slide3 from './sile3.avif';
import { useState, useContext } from 'react';
import UserContext from './context';

function App() {
  let [isModel, setIsModel] = useState(true);
  const { user, logout } = useContext(UserContext);

  return (
    <HashRouter>
      <Navbar bg="dark" variant="dark" expand="lg">
        <Container>
          <Navbar.Brand as={Link} to="/" onClick={() => setIsModel(true)}>
            <img
              src={bank}
              alt="Logo"
              className="d-inline-block align-top"
              style={{ width: "30px", height: "30px" }}
            />
            {" "}SanZen Bank
          </Navbar.Brand>
          <Navbar.Toggle aria-controls="navbar-nav" />
          <Navbar.Collapse id="navbar-nav">
            <Nav className="ms-auto align-items-center">
              <Nav.Link as={Link} to="/" onClick={() => setIsModel(true)}>Home</Nav.Link>

              {!user ? (
                <>
                  <Nav.Link as={Link} to="/register" onClick={() => setIsModel(false)}>Register</Nav.Link>
                  <Nav.Link as={Link} to="/login" onClick={() => setIsModel(false)}>Login</Nav.Link>
                </>
              ) : (
                <>
                  <Nav.Link as={Link} to="/deposit" onClick={() => setIsModel(false)}>Deposit</Nav.Link>
                  <Nav.Link as={Link} to="/cashback" onClick={() => setIsModel(false)}>Withdraw</Nav.Link>
                  <Nav.Link as={Link} to="/history" onClick={() => setIsModel(false)}>Tracking</Nav.Link>
                  <Nav.Link as={Link} to="/profile" onClick={() => setIsModel(false)}>Profile</Nav.Link>
                  {user.role === 'admin' && (
                    <Nav.Link as={Link} to="/alldata" onClick={() => setIsModel(false)}>All Data</Nav.Link>
                  )}
                  <span className="text-light mx-3 d-flex align-items-center">
                    {user.profilePhoto && (
                      <img
                        src={`http://localhost:8080${user.profilePhoto}`}
                        alt="Profile"
                        className="rounded-circle me-2"
                        style={{ width: "30px", height: "30px", objectFit: "cover", border: "1px solid white" }}
                      />
                    )}
                    Welcome, {user.name}
                  </span>
                  <Button variant="outline-danger" size="sm" onClick={logout}>Logout</Button>
                </>
              )}
            </Nav>
          </Navbar.Collapse>
        </Container>
      </Navbar>

      {isModel && (
        <Carousel className="custom-carousel" data-bs-theme="dark">
          <Carousel.Item className="custom-carousel-item">
            <img className="d-block w-100 custom-image" src={Slide1} alt="First slide" />
            <Carousel.Caption className="custom-caption">
              <h5 className="custom-caption-title">Register</h5>
              <p className="custom-caption-text">Time is money.</p>
            </Carousel.Caption>
          </Carousel.Item>

          <Carousel.Item className="custom-carousel-item">
            <img className="d-block w-100 custom-image" src={Slide2} alt="Second slide" />
            <Carousel.Caption className="custom-caption">
              <h5 className="custom-caption-title">Deposit</h5>
              <p className="custom-caption-text">Little by little, a little becomes a lot.</p>
            </Carousel.Caption>
          </Carousel.Item>

          <Carousel.Item className="custom-carousel-item">
            <img className="d-block w-100 custom-image" src={Slide3} alt="Third slide" />
            <Carousel.Caption className="custom-caption">
              <h5 className="custom-caption-title">Withdraw</h5>
              <p className="custom-caption-text">Do not spend your money before you have earned it.</p>
            </Carousel.Caption>
          </Carousel.Item>
        </Carousel>
      )}

      <Routes>
        <Route path="/register" element={<Register />} />
        <Route path="/login" element={<Login />} />
        <Route path="/deposit" element={<Deposit />} />
        <Route path="/cashback" element={<Cashback />} />
        <Route path="/history" element={<TransactionHistory />} />
        <Route path="/profile" element={<Profile />} />
        <Route path="/alldata" element={<Alldata />} />
      </Routes>

      <footer className="mt-5">&copy; SanZen Bank 2025</footer>
    </HashRouter>
  );
}

export default App;
